274	        options.onLine(rawLine);
275	      }
276	
277	      const line = parseIrcLine(rawLine);
278	      if (!line) {
279	        continue;
280	      }
281	
282	      if (line.command === "PING") {
283	        const payload =
284	          line.trailing != null ? line.trailing : line.params[0] != null ? line.params[0] : "";
285	        sendRaw(`PONG :${payload}`);
286	        continue;
287	      }
288	
289	      if (line.command === "NICK") {
290	        const prefix = parseIrcPrefix(line.prefix);
291	        if (prefix.nick && prefix.nick.toLowerCase() === currentNick.toLowerCase()) {
292	          const next =
293	            line.trailing != null
294	              ? line.trailing
295	              : line.params[0] != null
296	                ? line.params[0]
297	                : currentNick;
298	          currentNick = String(next).trim();
299	        }
300	        continue;
301	      }
302	
303	      if (!ready && IRC_NICK_COLLISION_CODES.has(line.command)) {
304	        if (tryRecoverNickCollision()) {
305	          continue;
306	        }
307	        const detail =
308	          line.trailing != null ? line.trailing : line.params.join(" ") || "nickname in use";
309	        fail(new Error(`IRC login failed (${line.command}): ${detail}`));
310	        close();
311	        return;
312	      }
313	
314	      if (!ready && IRC_ERROR_CODES.has(line.command)) {
315	        const detail =
316	          line.trailing != null ? line.trailing : line.params.join(" ") || "login rejected";
317	        fail(new Error(`IRC login failed (${line.command}): ${detail}`));
318	        close();
319	        return;
320	      }
321	
322	      if (line.command === "001") {
323	        ready = true;
324	        const nickParam = line.params[0];
325	        if (nickParam && nickParam.trim()) {
