301	
302	  const groupSystemPrompt = groupMatch.groupConfig?.systemPrompt?.trim() || undefined;
303	
304	  const ctxPayload = core.channel.reply.finalizeInboundContext({
305	    Body: body,
306	    RawBody: rawBody,
307	    CommandBody: rawBody,
308	    From: message.isGroup ? `irc:channel:${message.target}` : `irc:${senderDisplay}`,
309	    To: `irc:${peerId}`,
310	    SessionKey: route.sessionKey,
311	    AccountId: route.accountId,
312	    ChatType: message.isGroup ? "group" : "direct",
313	    ConversationLabel: fromLabel,
