5	export type IrcGroupMatch = {
6	  allowed: boolean;
7	  groupConfig?: IrcChannelConfig;
8	  wildcardConfig?: IrcChannelConfig;
9	  hasConfiguredGroups: boolean;
10	};
11	
12	export type IrcGroupAccessGate = {
13	  allowed: boolean;
14	  reason: string;
15	};
16	
17	export function resolveIrcGroupMatch(params: {
18	  groups?: Record<string, IrcChannelConfig>;
19	  target: string;
20	}): IrcGroupMatch {
21	  const groups = params.groups ?? {};
22	  const hasConfiguredGroups = Object.keys(groups).length > 0;
23	
24	  // IRC channel targets are case-insensitive, but config keys are plain strings.
25	  // To avoid surprising drops (e.g. "#TUIRC-DEV" vs "#tuirc-dev"), match
26	  // group config keys case-insensitively.
27	  const direct = groups[params.target];
28	  if (direct) {
29	    return {
30	      // "allowed" means the target matched an allowlisted key.
31	      // Explicit disables are handled later by resolveIrcGroupAccessGate.
32	      allowed: true,
33	      groupConfig: direct,
34	      wildcardConfig: groups["*"],
35	      hasConfiguredGroups,
36	    };
37	  }
38	
39	  const targetLower = params.target.toLowerCase();
40	  const directKey = Object.keys(groups).find((key) => key.toLowerCase() === targetLower);
41	  if (directKey) {
42	    const matched = groups[directKey];
43	    if (matched) {
44	      return {
45	        // "allowed" means the target matched an allowlisted key.
46	        // Explicit disables are handled later by resolveIrcGroupAccessGate.
47	        allowed: true,
48	        groupConfig: matched,
49	        wildcardConfig: groups["*"],
50	        hasConfiguredGroups,
51	      };
52	    }
53	  }
54	
55	  const wildcard = groups["*"];
56	  if (wildcard) {
57	    return {
58	      // "allowed" means the target matched an allowlisted key.
59	      // Explicit disables are handled later by resolveIrcGroupAccessGate.
60	      allowed: true,
61	      wildcardConfig: wildcard,
62	      hasConfiguredGroups,
63	    };
64	  }
65	  return {
66	    allowed: false,
67	    hasConfiguredGroups,
68	  };
69	}
70	
71	export function resolveIrcGroupAccessGate(params: {
72	  groupPolicy: IrcAccountConfig["groupPolicy"];
73	  groupMatch: IrcGroupMatch;
74	}): IrcGroupAccessGate {
75	  const policy = params.groupPolicy ?? "allowlist";
76	  if (policy === "disabled") {
77	    return { allowed: false, reason: "groupPolicy=disabled" };
78	  }
79	
80	  // In open mode, unconfigured channels are allowed (mention-gated) but explicit
81	  // per-channel/wildcard disables still apply.
82	  if (policy === "allowlist") {
83	    if (!params.groupMatch.hasConfiguredGroups) {
84	      return {
85	        allowed: false,
86	        reason: "groupPolicy=allowlist and no groups configured",
87	      };
88	    }
89	    if (!params.groupMatch.allowed) {
90	      return { allowed: false, reason: "not allowlisted" };
91	    }
92	  }
93	
94	  if (
95	    params.groupMatch.groupConfig?.enabled === false ||
96	    params.groupMatch.wildcardConfig?.enabled === false
97	  ) {
98	    return { allowed: false, reason: "disabled" };
99	  }
100	
101	  return { allowed: true, reason: policy === "open" ? "open" : "allowlisted" };
102	}
103	
104	export function resolveIrcRequireMention(params: {
105	  groupConfig?: IrcChannelConfig;
106	  wildcardConfig?: IrcChannelConfig;
107	}): boolean {
108	  if (params.groupConfig?.requireMention !== undefined) {
109	    return params.groupConfig.requireMention;
110	  }
111	  if (params.wildcardConfig?.requireMention !== undefined) {
112	    return params.wildcardConfig.requireMention;
113	  }
114	  return true;
115	}
116	
117	export function resolveIrcMentionGate(params: {
118	  isGroup: boolean;
119	  requireMention: boolean;
120	  wasMentioned: boolean;
121	  hasControlCommand: boolean;
122	  allowTextCommands: boolean;
123	  commandAuthorized: boolean;
124	}): { shouldSkip: boolean; reason: string } {
125	  if (!params.isGroup) {
126	    return { shouldSkip: false, reason: "direct" };
127	  }
128	  if (!params.requireMention) {
129	    return { shouldSkip: false, reason: "mention-not-required" };
130	  }
131	  if (params.wasMentioned) {
132	    return { shouldSkip: false, reason: "mentioned" };
133	  }
134	  if (params.hasControlCommand && params.allowTextCommands && params.commandAuthorized) {
135	    return { shouldSkip: false, reason: "authorized-command" };
136	  }
137	  return { shouldSkip: true, reason: "missing-mention" };
138	}
139	
140	export function resolveIrcGroupSenderAllowed(params: {
141	  groupPolicy: IrcAccountConfig["groupPolicy"];
142	  message: IrcInboundMessage;
143	  outerAllowFrom: string[];
144	  innerAllowFrom: string[];
145	  allowNameMatching?: boolean;
146	}): boolean {
147	  const policy = params.groupPolicy ?? "allowlist";
148	  const inner = normalizeIrcAllowlist(params.innerAllowFrom);
149	  const outer = normalizeIrcAllowlist(params.outerAllowFrom);
150	
151	  if (inner.length > 0) {
152	    return resolveIrcAllowlistMatch({
153	      allowFrom: inner,
154	      message: params.message,
155	      allowNameMatching: params.allowNameMatching,
156	    }).allowed;
157	  }
158	  if (outer.length > 0) {
159	    return resolveIrcAllowlistMatch({
160	      allowFrom: outer,
161	      message: params.message,
162	      allowNameMatching: params.allowNameMatching,
163	    }).allowed;
164	  }
165	  return policy === "open";
166	}
