21	export function parseIrcLine(line: string): ParsedIrcLine | null {
22	  const raw = line.replace(/[\r\n]+/g, "").trim();
23	  if (!raw) {
24	    return null;
25	  }
26	
27	  let cursor = raw;
28	  let prefix: string | undefined;
29	  if (cursor.startsWith(":")) {
30	    const idx = cursor.indexOf(" ");
31	    if (idx <= 1) {
32	      return null;
33	    }
34	    prefix = cursor.slice(1, idx);
35	    cursor = cursor.slice(idx + 1).trimStart();
36	  }
37	
38	  if (!cursor) {
39	    return null;
40	  }
41	
42	  const firstSpace = cursor.indexOf(" ");
43	  const command = (firstSpace === -1 ? cursor : cursor.slice(0, firstSpace)).trim();
44	  if (!command) {
45	    return null;
46	  }
47	
48	  cursor = firstSpace === -1 ? "" : cursor.slice(firstSpace + 1);
49	  const params: string[] = [];
50	  let trailing: string | undefined;
51	
52	  while (cursor.length > 0) {
53	    cursor = cursor.trimStart();
54	    if (!cursor) {
55	      break;
56	    }
57	    if (cursor.startsWith(":")) {
58	      trailing = cursor.slice(1);
59	      break;
60	    }
61	    const spaceIdx = cursor.indexOf(" ");
62	    if (spaceIdx === -1) {
63	      params.push(cursor);
64	      break;
65	    }
66	    params.push(cursor.slice(0, spaceIdx));
67	    cursor = cursor.slice(spaceIdx + 1);
68	  }
69	
70	  return {
71	    raw,
72	    prefix,
73	    command: command.toUpperCase(),
74	    params,
75	    trailing,
76	  };
77	}
