108	function decodeLiteralEscapes(input: string): string {
109	  // Defensive: this is not a full JS string unescaper.
110	  // It's just enough to catch common "\r\n" / "\u0001" style payloads.
111	  return input
112	    .replace(/\\r/g, "\r")
113	    .replace(/\\n/g, "\n")
114	    .replace(/\\t/g, "\t")
115	    .replace(/\\0/g, "\0")
116	    .replace(/\\x([0-9a-fA-F]{2})/g, (_, hex) => String.fromCharCode(Number.parseInt(hex, 16)))
117	    .replace(/\\u([0-9a-fA-F]{4})/g, (_, hex) => String.fromCharCode(Number.parseInt(hex, 16)));
118	}
