### 4. **Core Channel Plugin Implementation - `extensions/nostr/src/channel.ts`**

This file exports `nostrPlugin` as a `ChannelPlugin<ResolvedNostrAccount>` created via `createChatChannelPlugin()`:

```typescript
import { createChatChannelPlugin } from "openclaw/plugin-sdk/core";

export const nostrPlugin: ChannelPlugin<ResolvedNostrAccount> = createChatChannelPlugin({
  base: {
    id: "nostr",
    meta: {
      id: "nostr",
      label: "Nostr",
      selectionLabel: "Nostr",
      docsPath: "/channels/nostr",
      docsLabel: "nostr",
      blurb: "Decentralized DMs via Nostr relays (NIP-04)",
      order: 100,
    },
    capabilities: {
      chatTypes: ["direct"],    // or ["direct", "group"]
      media: false,             // Media attachment support
    },
    reload: { configPrefixes: ["channels.nostr"] },
    configSchema: buildChannelConfigSchema(NostrConfigSchema),
    setup: nostrSetupAdapter,
    setupWizard: nostrSetupWizard,
    config: {
      ...nostrConfigAdapter,
      isConfigured: (account) => account.configured,
      describeAccount: (account) => describeAccountSnapshot({...}),
    },
    messaging: {
      normalizeTarget: (target) => normalizePubkey(target.trim()),
      targetResolver: {
        looksLikeId: (input) => /^[0-9a-fA-F]{64}$|^npub1/.test(input.trim()),
        hint: "<npub|hex pubkey>",
      },
      resolveOutboundSessionRoute: (params) => resolveNostrOutboundSessionRoute(params),
    },
    status: createComputedAccountStatusAdapter<ResolvedNostrAccount>({...}),
    gateway: {
      startAccount: async (ctx) => {
        // Initialize Nostr bus, set up message handlers
        const bus = await startNostrBus({...});
        return {
          stop: () => bus.close(),
        };
      },
    },
  },
  pairing: {
    text: {
      idLabel: "nostrPubkey",
      message: "Your pairing request has been approved!",
      normalizeAllowEntry: (entry) => normalizePubkey(entry.trim()),
      notify: async ({ id, message }) => {
        // Send pairing approval via DM
        const bus = activeBuses.get(DEFAULT_ACCOUNT_ID);
        if (bus) await bus.sendDm(id, message);
      },
    },
  },
  security: {
    resolveDmPolicy: resolveNostrDmPolicy,
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ cfg, to, text, accountId }) => {
      const bus = activeBuses.get(accountId ?? DEFAULT_ACCOUNT_ID);
      if (!bus) throw new Error(`Nostr bus not running`);
      await bus.sendDm(normalizePubkey(to), text);
      return attachChannelToResult("nostr", {...});
    },
  },
});
```

