### 10. `extensions/pulseboard/src/types.ts`

Defines the TypeScript domain types for PulseBoard:

```typescript
import type { DmPolicy, GroupPolicy, GroupToolPolicyConfig, MarkdownConfig, OpenClawConfig, BaseProbeResult } from "./runtime-api.js";

// Per-board (group) channel config
export type PulseBoardGroupConfig = {
  requireMention?: boolean;
  tools?: GroupToolPolicyConfig;
  enabled?: boolean;
  allowFrom?: Array<string | number>;
  systemPrompt?: string;
};

// Account-level config (mirrors IrcAccountConfig shape)
export type PulseBoardAccountConfig = {
  name?: string;
  enabled?: boolean;
  serverUrl?: string;
  apiKey?: string;
  username?: string;
  dmPolicy?: DmPolicy;
  allowFrom?: Array<string | number>;
  groupPolicy?: GroupPolicy;
  groupAllowFrom?: Array<string | number>;
  groups?: Record<string, PulseBoardGroupConfig>;
  boards?: string[];           // boards to join on connect
  markdown?: MarkdownConfig;
};

// Root config (supports multi-account via accounts map)
export type PulseBoardConfig = PulseBoardAccountConfig & {
  accounts?: Record<string, PulseBoardAccountConfig>;
  defaultAccount?: string;
};

// OpenClaw config narrowed to include pulseboard section
export type CoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    pulseboard?: PulseBoardConfig;
  };
};

// An inbound PulseBoard message (from WebSocket event)
export type PulseBoardInboundMessage = {
  messageId: string;
  target: string;          // board name (#general) for groups, sender username for DMs
  rawTarget?: string;
  senderUser: string;
  text: string;
  timestamp: number;
  isGroup: boolean;
};

// Connection health check result
export type PulseBoardProbe = BaseProbeResult<string> & {
  serverUrl: string;
  username: string;
  latencyMs?: number;
};
```

