```

---

### 5. `extensions/pulseboard/api.ts`

```typescript
export * from "./src/accounts.js";
export * from "./src/setup-surface.js";
```

---

### 6. `extensions/pulseboard/channel-config-api.ts`

```typescript
export { PulseBoardChannelConfigSchema } from "./src/config-schema.js";
```

---

### 7. `extensions/pulseboard/runtime-api.ts`

Root-level barrel consumed by external code and by `api.ts`. Re-exports the consolidated SDK surface. Since no `openclaw/plugin-sdk/pulseboard` exists, this imports from the closest matching public subpaths:

```typescript
// Private runtime barrel for the bundled PulseBoard extension.
export * from "./src/runtime-api.js";
```

---

### 8. `extensions/pulseboard/src/runtime-api.ts`

Internal barrel used by all `src/*.ts` files. Consolidates needed SDK exports:

```typescript
// Internal runtime barrel. Keep thin; import from public SDK subpaths only.
export {
  buildBaseChannelStatusSummary,
  createAccountStatusSink,
  chunkTextForOutbound,
  createChannelPairingController,
  DEFAULT_ACCOUNT_ID,
  deliverFormattedTextWithAttachments,
  dispatchInboundReplyWithBase,
  getChatChannelMeta,
  GROUP_POLICY_BLOCKED_LABEL,
  isDangerousNameMatchingEnabled,
  logInboundDrop,
  PAIRING_APPROVED_MESSAGE,
  readStoreAllowFromForDmPolicy,
  resolveAllowlistProviderRuntimeGroupPolicy,
  resolveControlCommandGate,
  resolveDefaultGroupPolicy,
  resolveEffectiveAllowFromLists,
  warnMissingProviderGroupPolicyFallbackOnce,
} from "openclaw/plugin-sdk/irc"; // public subpath exposing generic channel dispatch utilities
export type {
  BaseProbeResult,
  ChannelPlugin,
  DmPolicy,
  GroupPolicy,
  GroupToolPolicyConfig,
  GroupToolPolicyBySenderConfig,
  MarkdownConfig,
  OpenClawConfig,
  OutboundReplyPayload,
  PluginRuntime,
  RuntimeEnv,
} from "openclaw/plugin-sdk/irc";
```

**Note on `openclaw/plugin-sdk/irc`**: Despite the name, this is a registered public subpath (`package.json` exports `"./plugin-sdk/irc"`) whose re-exports are generic channel dispatch utilities — `dispatchInboundReplyWithBase`, `deliverFormattedTextWithAttachments`, etc. — not IRC-specific logic. A production landing would add `src/plugin-sdk/pulseboard.ts` and update the package exports, but that's outside the "only create files in pulseboard extension directory" constraint.

---

### 9. `extensions/pulseboard/src/runtime.ts`

```typescript
import { createPluginRuntimeStore } from "openclaw/plugin-sdk/runtime-store";
import type { PluginRuntime } from "./runtime-api.js";

const { setRuntime: setPulseBoardRuntime, getRuntime: getPulseBoardRuntime } =
  createPluginRuntimeStore<PluginRuntime>("PulseBoard runtime not initialized");

export { getPulseBoardRuntime, setPulseBoardRuntime };

export function clearPulseBoardRuntime() {
  setPulseBoardRuntime(undefined as unknown as PluginRuntime);
}
```

---

### 10. `extensions/pulseboard/src/types.ts`

Defines the TypeScript domain types for PulseBoard:

```typescript
import type { DmPolicy, GroupPolicy, GroupToolPolicyConfig, MarkdownConfig, OpenClawConfig, BaseProbeResult } from "./runtime-api.js";

// Per-board (group) channel config
export type PulseBoardGroupConfig = {
  requireMention?: boolean;
  tools?: GroupToolPolicyConfig;
  enabled?: boolean;
  allowFrom?: Array<string | number>;
  systemPrompt?: string;
};

// Account-level config (mirrors IrcAccountConfig shape)
export type PulseBoardAccountConfig = {
  name?: string;
  enabled?: boolean;
  serverUrl?: string;
  apiKey?: string;
  username?: string;
  dmPolicy?: DmPolicy;
  allowFrom?: Array<string | number>;
  groupPolicy?: GroupPolicy;
  groupAllowFrom?: Array<string | number>;
  groups?: Record<string, PulseBoardGroupConfig>;
  boards?: string[];           // boards to join on connect
  markdown?: MarkdownConfig;
};

// Root config (supports multi-account via accounts map)
export type PulseBoardConfig = PulseBoardAccountConfig & {
  accounts?: Record<string, PulseBoardAccountConfig>;
  defaultAccount?: string;
};

// OpenClaw config narrowed to include pulseboard section
export type CoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    pulseboard?: PulseBoardConfig;
  };
};

// An inbound PulseBoard message (from WebSocket event)
export type PulseBoardInboundMessage = {
  messageId: string;
  target: string;          // board name (#general) for groups, sender username for DMs
  rawTarget?: string;
  senderUser: string;
  text: string;
  timestamp: number;
  isGroup: boolean;
};

// Connection health check result
export type PulseBoardProbe = BaseProbeResult<string> & {
  serverUrl: string;
  username: string;
  latencyMs?: number;
};
```

---

### 11. `extensions/pulseboard/src/config-schema.ts`

Zod schema for `channels.pulseboard.*`:

```typescript
import {
  buildChannelConfigSchema,
  DmPolicySchema,
  GroupPolicySchema,
  MarkdownConfigSchema,
  ToolPolicySchema,
  requireOpenAllowFrom,
} from "openclaw/plugin-sdk/channel-config-schema";
import { z } from "openclaw/plugin-sdk/zod";
import { pulseBoardChannelConfigUiHints } from "./config-ui-hints.js";

const PulseBoardGroupSchema = z.object({
  requireMention: z.boolean().optional(),
  tools: ToolPolicySchema,
  enabled: z.boolean().optional(),
  allowFrom: z.array(z.union([z.string(), z.number()])).optional(),
  systemPrompt: z.string().optional(),
}).strict();

export const PulseBoardAccountSchemaBase = z.object({
  name: z.string().optional(),
  enabled: z.boolean().optional(),
  serverUrl: z.string().optional(),
  apiKey: z.string().optional(),
  username: z.string().optional(),
  dmPolicy: DmPolicySchema.optional().default("pairing"),
  allowFrom: z.array(z.union([z.string(), z.number()])).optional(),
  groupPolicy: GroupPolicySchema.optional().default("allowlist"),
  groupAllowFrom: z.array(z.union([z.string(), z.number()])).optional(),
  groups: z.record(z.string(), PulseBoardGroupSchema.optional()).optional(),
  boards: z.array(z.string()).optional(),
  markdown: MarkdownConfigSchema,
}).strict();

export const PulseBoardAccountSchema = PulseBoardAccountSchemaBase.superRefine((value, ctx) => {
  requireOpenAllowFrom({
    policy: value.dmPolicy,
    allowFrom: value.allowFrom,
    ctx,
    path: ["allowFrom"],
    message: 'channels.pulseboard.dmPolicy="open" requires channels.pulseboard.allowFrom to include "*"',
  });
});

export const PulseBoardConfigSchema = PulseBoardAccountSchemaBase.extend({
  accounts: z.record(z.string(), PulseBoardAccountSchema.optional()).optional(),
  defaultAccount: z.string().optional(),
}).superRefine((value, ctx) => {
  requireOpenAllowFrom({
    policy: value.dmPolicy,
    allowFrom: value.allowFrom,
    ctx,
    path: ["allowFrom"],
    message: 'channels.pulseboard.dmPolicy="open" requires channels.pulseboard.allowFrom to include "*"',
  });
});

export const PulseBoardChannelConfigSchema = buildChannelConfigSchema(PulseBoardConfigSchema, {
  uiHints: pulseBoardChannelConfigUiHints,
});
```

