import { randomUUID } from "node:crypto";

/** Generate a unique message ID for a PulseBoard outbound message. */
export function makePulseBoardMessageId(): string {
  return randomUUID();
}

/** Strip NUL bytes and trim text for safe outbound delivery. */
export function sanitizePulseBoardOutboundText(text: string): string {
  return text.replace(/\x00/g, "").trim();
}

// ---------------------------------------------------------------------------
// PulseBoard wire protocol types
// ---------------------------------------------------------------------------

/** Inbound event types received from the PulseBoard server. */
export type PulseBoardServerEvent =
  | { type: "ready" }
  | {
      type: "message";
      from: string;
      to: string;
      text: string;
      messageId: string;
      timestamp: number;
    }
  | { type: "ack"; messageId: string }
  | { type: "pong" }
  | { type: "error"; message: string };

/**
 * Parse a raw JSON string from the WebSocket into a typed server event.
 * Returns null when the payload is not a recognized event.
 */
export function parsePulseBoardServerEvent(raw: string): PulseBoardServerEvent | null {
  let parsed: unknown;
  try {
    parsed = JSON.parse(raw);
  } catch {
    return null;
  }
  if (typeof parsed !== "object" || parsed === null) {
    return null;
  }
  const obj = parsed as Record<string, unknown>;
  const type = obj["type"];
  if (typeof type !== "string") {
    return null;
  }

  switch (type) {
    case "ready":
      return { type: "ready" };
    case "message": {
      const from = typeof obj["from"] === "string" ? obj["from"] : "";
      const to = typeof obj["to"] === "string" ? obj["to"] : "";
      const text = typeof obj["text"] === "string" ? obj["text"] : "";
      const messageId =
        typeof obj["messageId"] === "string" ? obj["messageId"] : makePulseBoardMessageId();
      const timestamp =
        typeof obj["timestamp"] === "number" ? obj["timestamp"] : Date.now();
      return { type: "message", from, to, text, messageId, timestamp };
    }
    case "ack": {
      const messageId =
        typeof obj["messageId"] === "string" ? obj["messageId"] : "";
      return { type: "ack", messageId };
    }
    case "pong":
      return { type: "pong" };
    case "error": {
      const message =
        typeof obj["message"] === "string" ? obj["message"] : "unknown error";
      return { type: "error", message };
    }
    default:
      return null;
  }
}

/**
 * Build the JSON payload to send a message over the PulseBoard WebSocket.
 * @param target - Board name (e.g. "#general") or recipient username.
 */
export function buildPulseBoardSendPayload(params: {
  target: string;
  text: string;
  messageId: string;
}): string {
  return JSON.stringify({
    type: "send",
    to: params.target,
    text: params.text,
    messageId: params.messageId,
  });
}

