export function parsePulseBoardServerEvent(raw: string): PulseBoardServerEvent | null {
  let parsed: unknown;
  try {
    parsed = JSON.parse(raw);
  } catch {
    return null;
  }
  if (typeof parsed !== "object" || parsed === null) {
    return null;
  }
  const obj = parsed as Record<string, unknown>;
  const type = obj["type"];
  if (typeof type !== "string") {
    return null;
  }

  switch (type) {
    case "ready":
      return { type: "ready" };
    case "message": {
      const from = typeof obj["from"] === "string" ? obj["from"] : "";
      const to = typeof obj["to"] === "string" ? obj["to"] : "";
      const text = typeof obj["text"] === "string" ? obj["text"] : "";
      const messageId =
        typeof obj["messageId"] === "string" ? obj["messageId"] : makePulseBoardMessageId();
      const timestamp =
        typeof obj["timestamp"] === "number" ? obj["timestamp"] : Date.now();
      return { type: "message", from, to, text, messageId, timestamp };
    }
    case "ack": {
      const messageId =
        typeof obj["messageId"] === "string" ? obj["messageId"] : "";
      return { type: "ack", messageId };
    }
    case "pong":
      return { type: "pong" };
    case "error": {
      const message =
        typeof obj["message"] === "string" ? obj["message"] : "unknown error";
      return { type: "error", message };
    }
    default:
      return null;
  }
}

/**
 * Build the JSON payload to send a message over the PulseBoard WebSocket.
 * @param target - Board name (e.g. "#general") or recipient username.
 */
export function buildPulseBoardSendPayload(params: {
  target: string;
  text: string;
  messageId: string;
}): string {
  return JSON.stringify({
    type: "send",
    to: params.target,
    text: params.text,
    messageId: params.messageId,
  });
}

