import {
  normalizePulseBoardAllowlist,
  resolvePulseBoardAllowlistMatch,
} from "./normalize.js";
import type { PulseBoardAccountConfig, PulseBoardGroupConfig, PulseBoardInboundMessage } from "./types.js";

export type PulseBoardGroupMatch = {
  allowed: boolean;
  groupConfig?: PulseBoardGroupConfig;
  wildcardConfig?: PulseBoardGroupConfig;
  hasConfiguredGroups: boolean;
};

export type PulseBoardGroupAccessGate = {
  allowed: boolean;
  reason: string;
};

/**
 * Match an inbound board target to the configured groups map.
 * Matching is case-insensitive; "*" is treated as a wildcard fallback.
 */
export function resolvePulseBoardGroupMatch(params: {
  groups?: Record<string, PulseBoardGroupConfig>;
  target: string;
}): PulseBoardGroupMatch {
  const groups = params.groups ?? {};
  const hasConfiguredGroups = Object.keys(groups).length > 0;

  const direct = groups[params.target];
  if (direct) {
    return {
      allowed: true,
      groupConfig: direct,
      wildcardConfig: groups["*"],
      hasConfiguredGroups,
    };
  }

  // Case-insensitive lookup for board names like "#General" vs "#general".
  const targetLower = params.target.toLowerCase();
  const directKey = Object.keys(groups).find((key) => key.toLowerCase() === targetLower);
  if (directKey) {
    const matched = groups[directKey];
    if (matched) {
      return {
        allowed: true,
        groupConfig: matched,
        wildcardConfig: groups["*"],
        hasConfiguredGroups,
      };
    }
  }

  const wildcard = groups["*"];
  if (wildcard) {
    return { allowed: true, wildcardConfig: wildcard, hasConfiguredGroups };
  }
  return { allowed: false, hasConfiguredGroups };
}

/**
 * Determine whether a matched board target is accessible given the group policy.
 */
export function resolvePulseBoardGroupAccessGate(params: {
  groupPolicy: PulseBoardAccountConfig["groupPolicy"];
  groupMatch: PulseBoardGroupMatch;
}): PulseBoardGroupAccessGate {
  const policy = params.groupPolicy ?? "allowlist";
  if (policy === "disabled") {
    return { allowed: false, reason: "groupPolicy=disabled" };
  }

  if (policy === "allowlist") {
    if (!params.groupMatch.hasConfiguredGroups) {
      return {
        allowed: false,
        reason: "groupPolicy=allowlist and no groups configured",
      };
    }
    if (!params.groupMatch.allowed) {
      return { allowed: false, reason: "not allowlisted" };
    }
  }

  if (
    params.groupMatch.groupConfig?.enabled === false ||
    params.groupMatch.wildcardConfig?.enabled === false
  ) {
    return { allowed: false, reason: "disabled" };
  }

  return { allowed: true, reason: policy === "open" ? "open" : "allowlisted" };
}

/** Check whether a mention is required for a given board group config. */
export function resolvePulseBoardRequireMention(params: {
  groupConfig?: PulseBoardGroupConfig;
  wildcardConfig?: PulseBoardGroupConfig;
}): boolean {
  if (params.groupConfig?.requireMention !== undefined) {
    return params.groupConfig.requireMention;
  }
  if (params.wildcardConfig?.requireMention !== undefined) {
    return params.wildcardConfig.requireMention;
  }
  // Default: require a mention in boards.
  return true;
}

/** Determine if an inbound group message should be skipped due to missing mention. */
export function resolvePulseBoardMentionGate(params: {
  isGroup: boolean;
  requireMention: boolean;
  wasMentioned: boolean;
  hasControlCommand: boolean;
  allowTextCommands: boolean;
  commandAuthorized: boolean;
}): { shouldSkip: boolean; reason: string } {
  if (!params.isGroup) {
    return { shouldSkip: false, reason: "direct" };
  }
  if (!params.requireMention) {
    return { shouldSkip: false, reason: "mention-not-required" };
  }
  if (params.wasMentioned) {
    return { shouldSkip: false, reason: "mentioned" };
  }
  if (params.hasControlCommand && params.allowTextCommands && params.commandAuthorized) {
    return { shouldSkip: false, reason: "authorized-command" };
  }
  return { shouldSkip: true, reason: "missing-mention" };
}

/** Check whether a sender is allowed to post in the board given the group policy. */
export function resolvePulseBoardGroupSenderAllowed(params: {
  groupPolicy: PulseBoardAccountConfig["groupPolicy"];
  message: PulseBoardInboundMessage;
  outerAllowFrom: string[];
  innerAllowFrom: string[];
}): boolean {
  const policy = params.groupPolicy ?? "allowlist";
  const inner = normalizePulseBoardAllowlist(params.innerAllowFrom);
  const outer = normalizePulseBoardAllowlist(params.outerAllowFrom);

  if (inner.length > 0) {
    return resolvePulseBoardAllowlistMatch({ allowFrom: inner, message: params.message }).allowed;
  }
  if (outer.length > 0) {
    return resolvePulseBoardAllowlistMatch({ allowFrom: outer, message: params.message }).allowed;
  }
  return policy === "open";
}

