import { buildPulseBoardSendPayload, parsePulseBoardServerEvent } from "./protocol.js";

// ---------------------------------------------------------------------------
// PulseBoard WebSocket client
//
// Wire protocol (fictional):
//   Client → Server: { type: "auth", apiKey, username }
//   Server → Client: { type: "ready" } | { type: "error", message }
//   Client → Server: { type: "join", board }
//   Client → Server: { type: "send", to, text, messageId }
//   Server → Client: { type: "message", from, to, text, messageId, timestamp }
//   Client → Server: { type: "ping" }
//   Server → Client: { type: "pong" }
// ---------------------------------------------------------------------------

export type PulseBoardServerEvent = ReturnType<typeof parsePulseBoardServerEvent>;

export interface PulseBoardClientOptions {
  serverUrl: string;
  apiKey: string;
  username: string;
  /** Boards to join immediately after auth (e.g. ["#general", "#dev"]). */
  boards?: string[];
  connectTimeoutMs?: number;
  abortSignal?: AbortSignal;
  onMessage?: (event: NonNullable<PulseBoardServerEvent>) => void | Promise<void>;
  onError?: (error: Error) => void;
  onDisconnect?: () => void;
}

export interface PulseBoardClient {
  isReady(): boolean;
  /** Send a message to a board ("#general") or DM a username. */
  sendMessage(target: string, text: string, messageId?: string): void;
  disconnect(reason?: string): void;
  readonly username: string;
}

/**
 * Connect to a PulseBoard server, authenticate, join boards, and return a
 * ready-to-use client handle.
 *
 * Resolves once the server acknowledges the auth handshake with `{ type: "ready" }`.
 * Rejects on timeout or auth error.
 */
export async function connectPulseBoardClient(
  opts: PulseBoardClientOptions,
): Promise<PulseBoardClient> {
  const connectTimeoutMs = opts.connectTimeoutMs ?? 10_000;

  return new Promise<PulseBoardClient>((resolve, reject) => {
    let settled = false;
    let ready = false;

    const settle = (err?: Error) => {
      if (settled) return;
      settled = true;
      clearTimeout(timeoutHandle);
      if (err) {
        reject(err);
      }
    };

    const timeoutHandle = setTimeout(() => {
      settle(new Error(`PulseBoard connection timed out after ${connectTimeoutMs}ms`));
      try {
        ws.close();
      } catch {
        // ignore close errors during timeout
      }
    }, connectTimeoutMs);

    // Use the global WebSocket available in Node 22+.
    // eslint-disable-next-line no-undef
    const ws = new WebSocket(opts.serverUrl);

    opts.abortSignal?.addEventListener("abort", () => {
      settle(new Error("PulseBoard connection aborted"));
      try {
        ws.close();
      } catch {
        // ignore
      }
    });

    ws.addEventListener("open", () => {
      // Send auth handshake immediately after the socket opens.
      ws.send(
        JSON.stringify({
          type: "auth",
          apiKey: opts.apiKey,
          username: opts.username,
        }),
      );
    });

    ws.addEventListener("message", async (evt: MessageEvent<string>) => {
      const event = parsePulseBoardServerEvent(String(evt.data));
      if (!event) {
        return;
      }

      if (!ready) {
        // We are waiting for the auth acknowledgement.
        if (event.type === "ready") {
          ready = true;
          // Join configured boards.
          for (const board of opts.boards ?? []) {
            ws.send(JSON.stringify({ type: "join", board }));
          }
          settle();
          resolve(client);
          return;
        }
        if (event.type === "error") {
          settle(new Error(`PulseBoard auth error: ${event.message}`));
          ws.close();
          return;
        }
        return;
      }

      // Forward all post-auth events to the caller.
      if (opts.onMessage) {
        try {
          await opts.onMessage(event);
        } catch (err) {
          opts.onError?.(err instanceof Error ? err : new Error(String(err)));
        }
      }
    });

    ws.addEventListener("error", (evt: Event) => {
      const msg = "message" in evt ? String((evt as ErrorEvent).message) : "WebSocket error";
      const err = new Error(`PulseBoard WebSocket error: ${msg}`);
      if (!ready) {
        settle(err);
      } else {
        opts.onError?.(err);
      }
    });

    ws.addEventListener("close", () => {
      if (!ready) {
        settle(new Error("PulseBoard WebSocket closed before auth completed"));
      } else {
        opts.onDisconnect?.();
      }
    });

    const client: PulseBoardClient = {
      username: opts.username,
      isReady() {
        return ready && ws.readyState === WebSocket.OPEN;
      },
      sendMessage(target: string, text: string, messageId?: string) {
        const id = messageId ?? crypto.randomUUID();
        ws.send(buildPulseBoardSendPayload({ target, text, messageId: id }));
      },
      disconnect(reason?: string) {
        ready = false;
        try {
          if (ws.readyState === WebSocket.OPEN || ws.readyState === WebSocket.CONNECTING) {
            if (reason) {
              ws.send(JSON.stringify({ type: "disconnect", reason }));
            }
            ws.close();
          }
        } catch {
          // ignore errors on disconnect
        }
      },
    };
  });
}

