import { describe, expect, it, afterEach } from "vitest";
import {
  listPulseBoardAccountIds,
  resolveDefaultPulseBoardAccountId,
  resolvePulseBoardAccount,
  listEnabledPulseBoardAccounts,
} from "./accounts.js";
import type { CoreConfig } from "./types.js";

const baseConfig = (): CoreConfig => ({} as CoreConfig);

const withPulseBoard = (extra: Record<string, unknown> = {}): CoreConfig =>
  ({
    channels: {
      pulseboard: {
        serverUrl: "wss://pb.example.com",
        apiKey: "key123",
        username: "bot",
        ...extra,
      },
    },
  }) as unknown as CoreConfig;

describe("listPulseBoardAccountIds", () => {
  it("returns empty array when pulseboard is not configured", () => {
    expect(listPulseBoardAccountIds(baseConfig())).toEqual([]);
  });

  it("returns default account id when top-level config is present", () => {
    const ids = listPulseBoardAccountIds(withPulseBoard());
    expect(ids).toContain("default");
  });

  it("includes named accounts", () => {
    const cfg = withPulseBoard({
      accounts: { work: { serverUrl: "wss://work.example.com", apiKey: "k", username: "bot" } },
    });
    const ids = listPulseBoardAccountIds(cfg);
    expect(ids).toContain("work");
  });
});

describe("resolveDefaultPulseBoardAccountId", () => {
  it("returns default when no defaultAccount is set", () => {
    expect(resolveDefaultPulseBoardAccountId(withPulseBoard())).toBe("default");
  });

  it("returns configured defaultAccount", () => {
    const cfg = withPulseBoard({
      accounts: { work: {} },
      defaultAccount: "work",
    });
    expect(resolveDefaultPulseBoardAccountId(cfg)).toBe("work");
  });
});

describe("resolvePulseBoardAccount", () => {
  it("marks account as configured when serverUrl, apiKey, and username are present", () => {
    const account = resolvePulseBoardAccount({ cfg: withPulseBoard() });
    expect(account.configured).toBe(true);
    expect(account.serverUrl).toBe("wss://pb.example.com");
    expect(account.apiKey).toBe("key123");
    expect(account.username).toBe("bot");
  });

  it("marks account as not configured when apiKey is missing", () => {
    const account = resolvePulseBoardAccount({
      cfg: withPulseBoard({ apiKey: undefined }),
    });
    expect(account.configured).toBe(false);
  });

  it("marks account as not configured when serverUrl is missing", () => {
    const account = resolvePulseBoardAccount({
      cfg: withPulseBoard({ serverUrl: undefined }),
    });
    expect(account.configured).toBe(false);
  });

  it("marks account as not configured when username is missing", () => {
    const account = resolvePulseBoardAccount({
      cfg: withPulseBoard({ username: undefined }),
    });
    expect(account.configured).toBe(false);
  });

  it("respects enabled=false", () => {
    const account = resolvePulseBoardAccount({
      cfg: withPulseBoard({ enabled: false }),
    });
    expect(account.enabled).toBe(false);
  });

  describe("env var fallback", () => {
    afterEach(() => {
      delete process.env.PULSEBOARD_SERVER_URL;
      delete process.env.PULSEBOARD_API_KEY;
      delete process.env.PULSEBOARD_USERNAME;
    });

    it("reads serverUrl from PULSEBOARD_SERVER_URL", () => {
      process.env.PULSEBOARD_SERVER_URL = "wss://env.example.com";
      process.env.PULSEBOARD_API_KEY = "envkey";
      process.env.PULSEBOARD_USERNAME = "envbot";
      const cfg = { channels: { pulseboard: {} } } as unknown as CoreConfig;
      const account = resolvePulseBoardAccount({ cfg });
      expect(account.serverUrl).toBe("wss://env.example.com");
      expect(account.configured).toBe(true);
    });

    it("config values take precedence over env vars", () => {
      process.env.PULSEBOARD_SERVER_URL = "wss://env.example.com";
      const account = resolvePulseBoardAccount({ cfg: withPulseBoard() });
      expect(account.serverUrl).toBe("wss://pb.example.com");
    });
  });
});

describe("listEnabledPulseBoardAccounts", () => {
  it("returns only enabled accounts", () => {
    const cfg = withPulseBoard({
      accounts: {
        disabled: { enabled: false, serverUrl: "wss://x.com", apiKey: "k", username: "u" },
      },
    });
    const accounts = listEnabledPulseBoardAccounts(cfg);
    for (const account of accounts) {
      expect(account.enabled).toBe(true);
    }
  });
});

