import { describe, expect, it } from "vitest";
import { PulseBoardConfigSchema, PulseBoardAccountSchema } from "./config-schema.js";

describe("PulseBoardConfigSchema", () => {
  it("accepts a minimal valid config", () => {
    const result = PulseBoardConfigSchema.safeParse({
      serverUrl: "wss://pb.example.com",
      apiKey: "key",
      username: "bot",
    });
    expect(result.success).toBe(true);
  });

  it("accepts an empty object (all fields optional)", () => {
    expect(PulseBoardConfigSchema.safeParse({}).success).toBe(true);
  });

  it('requires allowFrom=["*"] when dmPolicy="open"', () => {
    const result = PulseBoardConfigSchema.safeParse({
      dmPolicy: "open",
    });
    expect(result.success).toBe(false);
  });

  it('allows dmPolicy="open" when allowFrom includes "*"', () => {
    const result = PulseBoardConfigSchema.safeParse({
      dmPolicy: "open",
      allowFrom: ["*"],
    });
    expect(result.success).toBe(true);
  });

  it("rejects unknown fields", () => {
    const result = PulseBoardConfigSchema.safeParse({
      unknownField: "value",
    });
    expect(result.success).toBe(false);
  });

  it("accepts boards array", () => {
    const result = PulseBoardConfigSchema.safeParse({
      boards: ["#general", "#dev"],
    });
    expect(result.success).toBe(true);
  });

  it("accepts groups config with wildcard", () => {
    const result = PulseBoardConfigSchema.safeParse({
      groupPolicy: "allowlist",
      groups: {
        "#general": { requireMention: false },
        "*": { requireMention: true },
      },
    });
    expect(result.success).toBe(true);
  });

  it("accepts named accounts", () => {
    const result = PulseBoardConfigSchema.safeParse({
      accounts: {
        work: {
          serverUrl: "wss://work.example.com",
          apiKey: "workkey",
          username: "workbot",
        },
      },
    });
    expect(result.success).toBe(true);
  });
});

describe("PulseBoardAccountSchema", () => {
  it('rejects dmPolicy="open" without allowFrom wildcard', () => {
    const result = PulseBoardAccountSchema.safeParse({ dmPolicy: "open" });
    expect(result.success).toBe(false);
  });

  it("defaults dmPolicy to pairing", () => {
    const result = PulseBoardAccountSchema.safeParse({});
    expect(result.success).toBe(true);
    if (result.success) {
      expect(result.data.dmPolicy).toBe("pairing");
    }
  });
});

