import { describe, expect, it } from "vitest";
import {
  makePulseBoardMessageId,
  sanitizePulseBoardOutboundText,
  parsePulseBoardServerEvent,
  buildPulseBoardSendPayload,
} from "./protocol.js";

describe("makePulseBoardMessageId", () => {
  it("returns a non-empty UUID-shaped string", () => {
    const id = makePulseBoardMessageId();
    expect(typeof id).toBe("string");
    expect(id.length).toBeGreaterThan(0);
    // Standard UUID v4 pattern
    expect(id).toMatch(/^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i);
  });

  it("returns unique ids", () => {
    const ids = new Set(Array.from({ length: 10 }, () => makePulseBoardMessageId()));
    expect(ids.size).toBe(10);
  });
});

describe("sanitizePulseBoardOutboundText", () => {
  it("trims whitespace", () => {
    expect(sanitizePulseBoardOutboundText("  hello  ")).toBe("hello");
  });

  it("strips NUL bytes", () => {
    expect(sanitizePulseBoardOutboundText("hel\x00lo")).toBe("hello");
  });

  it("preserves normal text", () => {
    expect(sanitizePulseBoardOutboundText("Hello, world!")).toBe("Hello, world!");
  });
});

describe("parsePulseBoardServerEvent", () => {
  it("parses a ready event", () => {
    const event = parsePulseBoardServerEvent(JSON.stringify({ type: "ready" }));
    expect(event).toEqual({ type: "ready" });
  });

  it("parses a message event", () => {
    const event = parsePulseBoardServerEvent(
      JSON.stringify({
        type: "message",
        from: "alice",
        to: "#general",
        text: "hello",
        messageId: "msg1",
        timestamp: 1234567890,
      }),
    );
    expect(event).toEqual({
      type: "message",
      from: "alice",
      to: "#general",
      text: "hello",
      messageId: "msg1",
      timestamp: 1234567890,
    });
  });

  it("parses an ack event", () => {
    const event = parsePulseBoardServerEvent(JSON.stringify({ type: "ack", messageId: "msg1" }));
    expect(event).toEqual({ type: "ack", messageId: "msg1" });
  });

  it("parses an error event", () => {
    const event = parsePulseBoardServerEvent(
      JSON.stringify({ type: "error", message: "auth failed" }),
    );
    expect(event).toEqual({ type: "error", message: "auth failed" });
  });

  it("parses a pong event", () => {
    const event = parsePulseBoardServerEvent(JSON.stringify({ type: "pong" }));
    expect(event).toEqual({ type: "pong" });
  });

  it("returns null for invalid JSON", () => {
    expect(parsePulseBoardServerEvent("not json")).toBeNull();
  });

  it("returns null for unknown event type", () => {
    expect(parsePulseBoardServerEvent(JSON.stringify({ type: "unknown" }))).toBeNull();
  });

  it("returns null for non-object payload", () => {
    expect(parsePulseBoardServerEvent(JSON.stringify(42))).toBeNull();
  });

  it("fills in default messageId for message events with missing id", () => {
    const event = parsePulseBoardServerEvent(
      JSON.stringify({ type: "message", from: "bob", to: "alice", text: "hi" }),
    );
    expect(event?.type).toBe("message");
    if (event?.type === "message") {
      expect(typeof event.messageId).toBe("string");
      expect(event.messageId.length).toBeGreaterThan(0);
    }
  });
});

describe("buildPulseBoardSendPayload", () => {
  it("builds a valid JSON send payload", () => {
    const payload = buildPulseBoardSendPayload({
      target: "#general",
      text: "Hello!",
      messageId: "msg1",
    });
    const parsed = JSON.parse(payload);
    expect(parsed).toEqual({
      type: "send",
      to: "#general",
      text: "Hello!",
      messageId: "msg1",
    });
  });
});

