import { describe, expect, it, vi, beforeEach } from "vitest";
import { probePulseBoard } from "./probe.js";
import type { CoreConfig } from "./types.js";

vi.mock("./client.js", () => ({
  connectPulseBoardClient: vi.fn(),
}));

import { connectPulseBoardClient } from "./client.js";

const withPulseBoard = (extra: Record<string, unknown> = {}): CoreConfig =>
  ({
    channels: {
      pulseboard: {
        serverUrl: "wss://pb.example.com",
        apiKey: "key123",
        username: "bot",
        ...extra,
      },
    },
  }) as unknown as CoreConfig;

describe("probePulseBoard", () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it("returns ok=false with error when not configured", async () => {
    const result = await probePulseBoard({} as CoreConfig);
    expect(result.ok).toBe(false);
    expect(result.error).toMatch(/missing/i);
  });

  it("returns ok=true with latencyMs on successful connect", async () => {
    const mockClient = {
      isReady: () => true,
      disconnect: vi.fn(),
      sendMessage: vi.fn(),
      username: "bot",
    };
    vi.mocked(connectPulseBoardClient).mockResolvedValueOnce(mockClient);

    const result = await probePulseBoard(withPulseBoard());
    expect(result.ok).toBe(true);
    expect(typeof result.latencyMs).toBe("number");
    expect(mockClient.disconnect).toHaveBeenCalledWith("probe");
  });

  it("returns ok=false with error message on connect failure", async () => {
    vi.mocked(connectPulseBoardClient).mockRejectedValueOnce(
      new Error("connection refused"),
    );

    const result = await probePulseBoard(withPulseBoard());
    expect(result.ok).toBe(false);
    expect(result.error).toContain("connection refused");
  });

  it("includes serverUrl and username in result", async () => {
    vi.mocked(connectPulseBoardClient).mockRejectedValueOnce(new Error("err"));

    const result = await probePulseBoard(withPulseBoard());
    expect(result.serverUrl).toBe("wss://pb.example.com");
    expect(result.username).toBe("bot");
  });
});

