import { connectPulseBoardClient } from "./client.js";
import { sendMessagePulseBoard } from "./send.js";
import type { CoreConfig } from "./types.js";

const withPulseBoard = (): CoreConfig =>
  ({
    channels: {
      pulseboard: {
        serverUrl: "wss://pb.example.com",
        apiKey: "key123",
        username: "bot",
      },
    },
  }) as unknown as CoreConfig;

describe("sendMessagePulseBoard", () => {
  const mockClient = {
    isReady: () => true,
    sendMessage: vi.fn(),
    disconnect: vi.fn(),
    username: "bot",
  };

  beforeEach(() => {
    vi.clearAllMocks();
    vi.mocked(connectPulseBoardClient).mockResolvedValue(mockClient);
  });

  it("throws when not configured", async () => {
    await expect(
      sendMessagePulseBoard("alice", "hello", { cfg: {} as CoreConfig }),
    ).rejects.toThrow(/not configured/i);
  });

  it("throws on invalid target", async () => {
    await expect(
      sendMessagePulseBoard("alice bob", "hello", { cfg: withPulseBoard() }),
    ).rejects.toThrow(/invalid PulseBoard target/i);
  });

  it("throws on empty message", async () => {
