import type {
  BaseProbeResult,
  DmPolicy,
  GroupPolicy,
  GroupToolPolicyConfig,
  MarkdownConfig,
  OpenClawConfig,
} from "./runtime-api.js";

/** Per-board (group channel) configuration. */
export type PulseBoardGroupConfig = {
  requireMention?: boolean;
  tools?: GroupToolPolicyConfig;
  enabled?: boolean;
  allowFrom?: Array<string | number>;
  systemPrompt?: string;
};

/** Account-level PulseBoard configuration. */
export type PulseBoardAccountConfig = {
  name?: string;
  enabled?: boolean;
  serverUrl?: string;
  apiKey?: string;
  username?: string;
  dmPolicy?: DmPolicy;
  allowFrom?: Array<string | number>;
  groupPolicy?: GroupPolicy;
  groupAllowFrom?: Array<string | number>;
  /** Per-board config, keyed by board name (e.g. "#general") or "*" wildcard. */
  groups?: Record<string, PulseBoardGroupConfig>;
  /** Boards to auto-join on connect (e.g. ["#general", "#dev"]). */
  boards?: string[];
  markdown?: MarkdownConfig;
};

/** Root PulseBoard config — supports multi-account via accounts map. */
export type PulseBoardConfig = PulseBoardAccountConfig & {
  accounts?: Record<string, PulseBoardAccountConfig>;
  defaultAccount?: string;
};

/** OpenClaw config narrowed to include the pulseboard section. */
export type CoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    pulseboard?: PulseBoardConfig;
  };
};

/** An inbound PulseBoard message received from the WebSocket connection. */
export type PulseBoardInboundMessage = {
  messageId: string;
  /** Board name (e.g. "#general") for group messages; sender username for DMs. */
  target: string;
  /** Raw target value as sent by the server. */
  rawTarget?: string;
  senderUser: string;
  text: string;
  timestamp: number;
  isGroup: boolean;
};

/** Connection health-check result. */
export type PulseBoardProbe = BaseProbeResult<string> & {
  serverUrl: string;
  username: string;
  latencyMs?: number;
};

