import { describe, expect, it, vi, beforeEach } from "vitest";

vi.mock("./runtime.js", () => ({
  getPulseBoardRuntime: vi.fn(),
}));

vi.mock("./send.js", () => ({
  sendMessagePulseBoard: vi.fn().mockResolvedValue({ messageId: "msg-out", target: "alice" }),
}));

vi.mock("./runtime-api.js", () => ({
  GROUP_POLICY_BLOCKED_LABEL: { channel: "blocked by channel policy" },
  createChannelPairingController: vi.fn(),
  deliverFormattedTextWithAttachments: vi.fn().mockResolvedValue(undefined),
  dispatchInboundReplyWithBase: vi.fn().mockResolvedValue(undefined),
  isDangerousNameMatchingEnabled: vi.fn().mockReturnValue(false),
  logInboundDrop: vi.fn(),
  readStoreAllowFromForDmPolicy: vi.fn().mockResolvedValue([]),
  resolveAllowlistProviderRuntimeGroupPolicy: vi.fn().mockReturnValue({
    groupPolicy: "allowlist",
    providerMissingFallbackApplied: false,
  }),
  resolveControlCommandGate: vi.fn().mockReturnValue({
    commandAuthorized: false,
    shouldBlock: false,
  }),
  resolveDefaultGroupPolicy: vi.fn().mockReturnValue("allowlist"),
  resolveEffectiveAllowFromLists: vi.fn().mockReturnValue({
    effectiveAllowFrom: [],
    effectiveGroupAllowFrom: [],
  }),
  warnMissingProviderGroupPolicyFallbackOnce: vi.fn(),
}));

import { getPulseBoardRuntime } from "./runtime.js";
import {
  createChannelPairingController,
  dispatchInboundReplyWithBase,
  readStoreAllowFromForDmPolicy,
  resolveAllowlistProviderRuntimeGroupPolicy,
  resolveControlCommandGate,
  resolveEffectiveAllowFromLists,
} from "./runtime-api.js";
import { handlePulseBoardInbound } from "./inbound.js";
import type { ResolvedPulseBoardAccount } from "./accounts.js";
import type { CoreConfig, PulseBoardInboundMessage } from "./types.js";

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function makeDmMessage(
  overrides: Partial<PulseBoardInboundMessage> = {},
): PulseBoardInboundMessage {
  return {
    messageId: "msg1",
    target: "alice",
    senderUser: "alice",
    text: "Hello bot",
    timestamp: 1_000_000,
    isGroup: false,
    ...overrides,
  };
}

function makeGroupMessage(
  overrides: Partial<PulseBoardInboundMessage> = {},
): PulseBoardInboundMessage {
  return {
    messageId: "msg2",
    target: "#general",
    senderUser: "alice",
    text: "Hello board",
    timestamp: 1_000_000,
    isGroup: true,
    ...overrides,
  };
}

function makeAccount(
  overrides: Partial<ResolvedPulseBoardAccount["config"]> = {},
): ResolvedPulseBoardAccount {
  return {
    accountId: "default",
    enabled: true,
    configured: true,
    serverUrl: "wss://pb.example.com",
    apiKey: "key123",
    username: "bot",
    config: {
      dmPolicy: "open",
      allowFrom: ["*"],
      groupPolicy: "allowlist",
      ...overrides,
    },
  } as unknown as ResolvedPulseBoardAccount;
}

function makeConfig(extra: Record<string, unknown> = {}): CoreConfig {
  return {
    channels: {
      pulseboard: {
        serverUrl: "wss://pb.example.com",
        apiKey: "key123",
        username: "bot",
      },
    },
    ...extra,
  } as unknown as CoreConfig;
}

function makeRuntime(log?: vi.MockedFunction<(msg: string) => void>) {
  const mockLog = log ?? vi.fn();
  const mockError = vi.fn();
  const route = { agentId: "agent1", sessionKey: "sess1", accountId: "default" };
  const storePath = "/tmp/store";
  return {
    runtime: {
      log: mockLog,
      error: mockError,
    },
    mockLog,
    mockError,
    core: {
      channel: {
        commands: {
          shouldHandleTextCommands: vi.fn().mockReturnValue(true),
        },
        text: {
          hasControlCommand: vi.fn().mockReturnValue(false),
        },
        mentions: {
          buildMentionRegexes: vi.fn().mockReturnValue([]),
          matchesMentionPatterns: vi.fn().mockReturnValue(false),
        },
        routing: {
          resolveAgentRoute: vi.fn().mockReturnValue(route),
        },
        session: {
          resolveStorePath: vi.fn().mockReturnValue(storePath),
          readSessionUpdatedAt: vi.fn().mockReturnValue(undefined),
        },
        reply: {
          resolveEnvelopeFormatOptions: vi.fn().mockReturnValue({}),
          formatAgentEnvelope: vi.fn().mockReturnValue("formatted body"),
          finalizeInboundContext: vi.fn().mockReturnValue({ Body: "formatted body" }),
          resolveEnvelopeFormatOptions: vi.fn().mockReturnValue({}),
        },
      },
    },
  };
}

function makePairing() {
  return {
    readStoreForDmPolicy: vi.fn().mockResolvedValue([]),
    issueChallenge: vi.fn().mockResolvedValue(undefined),
  };
}

// ---------------------------------------------------------------------------
// Setup
// ---------------------------------------------------------------------------

beforeEach(() => {
  vi.clearAllMocks();

  const { core } = makeRuntime();
  vi.mocked(getPulseBoardRuntime).mockReturnValue(core as never);

  const pairing = makePairing();
  vi.mocked(createChannelPairingController).mockReturnValue(pairing as never);

  vi.mocked(resolveAllowlistProviderRuntimeGroupPolicy).mockReturnValue({
    groupPolicy: "allowlist",
    providerMissingFallbackApplied: false,
  });
  vi.mocked(resolveEffectiveAllowFromLists).mockReturnValue({
    effectiveAllowFrom: ["alice"],
    effectiveGroupAllowFrom: ["alice"],
  });
  vi.mocked(resolveControlCommandGate).mockReturnValue({
    commandAuthorized: false,
    shouldBlock: false,
  });
  vi.mocked(readStoreAllowFromForDmPolicy).mockResolvedValue([]);
});

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

describe("handlePulseBoardInbound", () => {
  it("ignores empty body", async () => {
    const { core, runtime } = makeRuntime();
    vi.mocked(getPulseBoardRuntime).mockReturnValue(core as never);

    await handlePulseBoardInbound({
      message: makeDmMessage({ text: "   " }),
      account: makeAccount(),
      config: makeConfig(),
      runtime,
    });

    expect(dispatchInboundReplyWithBase).not.toHaveBeenCalled();
  });

  it("updates statusSink with lastInboundAt", async () => {
    const { core, runtime } = makeRuntime();
    vi.mocked(getPulseBoardRuntime).mockReturnValue(core as never);
    const statusSink = vi.fn();

    await handlePulseBoardInbound({
      message: makeDmMessage(),
      account: makeAccount({ dmPolicy: "open", allowFrom: ["*"] }),
      config: makeConfig(),
      runtime,
      statusSink,
    });

    expect(statusSink).toHaveBeenCalledWith(
      expect.objectContaining({ lastInboundAt: 1_000_000 }),
    );
  });

  describe("DM policy", () => {
    it("drops DM when dmPolicy=disabled", async () => {
      const { core, runtime } = makeRuntime();
      vi.mocked(getPulseBoardRuntime).mockReturnValue(core as never);

      await handlePulseBoardInbound({
        message: makeDmMessage(),
        account: makeAccount({ dmPolicy: "disabled" }),
        config: makeConfig(),
        runtime,
      });

      expect(dispatchInboundReplyWithBase).not.toHaveBeenCalled();
    });

    it("issues pairing challenge when dmPolicy=pairing and sender not in allowlist", async () => {
      const { core, runtime } = makeRuntime();
      vi.mocked(getPulseBoardRuntime).mockReturnValue(core as never);

      const pairing = makePairing();
      vi.mocked(createChannelPairingController).mockReturnValue(pairing as never);

      // Sender not in effective allowlist
      vi.mocked(resolveEffectiveAllowFromLists).mockReturnValue({
        effectiveAllowFrom: [],
        effectiveGroupAllowFrom: [],
      });

      await handlePulseBoardInbound({
        message: makeDmMessage({ senderUser: "stranger", target: "stranger" }),
        account: makeAccount({ dmPolicy: "pairing" }),
        config: makeConfig(),
        runtime,
      });

      expect(pairing.issueChallenge).toHaveBeenCalledWith(
        expect.objectContaining({ senderId: "stranger" }),
      );
      expect(dispatchInboundReplyWithBase).not.toHaveBeenCalled();
    });

    it("does not dispatch when dmPolicy=allowlist and sender not in list", async () => {
      const { core, runtime } = makeRuntime();
      vi.mocked(getPulseBoardRuntime).mockReturnValue(core as never);

      vi.mocked(resolveEffectiveAllowFromLists).mockReturnValue({
        effectiveAllowFrom: ["bob"],
        effectiveGroupAllowFrom: [],
      });

      await handlePulseBoardInbound({
        message: makeDmMessage({ senderUser: "alice", target: "alice" }),
        account: makeAccount({ dmPolicy: "allowlist", allowFrom: ["bob"] }),
        config: makeConfig(),
        runtime,
      });

      expect(dispatchInboundReplyWithBase).not.toHaveBeenCalled();
    });

    it("dispatches DM when dmPolicy=open", async () => {
      const { core, runtime } = makeRuntime();
      vi.mocked(getPulseBoardRuntime).mockReturnValue(core as never);

      vi.mocked(resolveEffectiveAllowFromLists).mockReturnValue({
        effectiveAllowFrom: ["*"],
        effectiveGroupAllowFrom: [],
      });

      await handlePulseBoardInbound({
        message: makeDmMessage(),
        account: makeAccount({ dmPolicy: "open", allowFrom: ["*"] }),
        config: makeConfig(),
        runtime,
      });

      expect(dispatchInboundReplyWithBase).toHaveBeenCalledOnce();
    });

    it("dispatches DM when sender is in allowlist", async () => {
      const { core, runtime } = makeRuntime();
      vi.mocked(getPulseBoardRuntime).mockReturnValue(core as never);

      vi.mocked(resolveEffectiveAllowFromLists).mockReturnValue({
        effectiveAllowFrom: ["alice"],
        effectiveGroupAllowFrom: [],
      });

      await handlePulseBoardInbound({
        message: makeDmMessage({ senderUser: "alice", target: "alice" }),
        account: makeAccount({ dmPolicy: "allowlist", allowFrom: ["alice"] }),
        config: makeConfig(),
        runtime,
      });

      expect(dispatchInboundReplyWithBase).toHaveBeenCalledOnce();
    });
  });

  describe("group policy", () => {
    it("drops group message when groupPolicy blocks the board", async () => {
      const { core, runtime } = makeRuntime();
      vi.mocked(getPulseBoardRuntime).mockReturnValue(core as never);

      vi.mocked(resolveAllowlistProviderRuntimeGroupPolicy).mockReturnValue({
        groupPolicy: "disabled",
        providerMissingFallbackApplied: false,
      });

      await handlePulseBoardInbound({
        message: makeGroupMessage(),
        account: makeAccount({ groupPolicy: "disabled" }),
        config: makeConfig(),
        runtime,
      });

      expect(dispatchInboundReplyWithBase).not.toHaveBeenCalled();
    });

    it("drops group message when sender not in effective group allowlist", async () => {
      const { core, runtime } = makeRuntime();
      vi.mocked(getPulseBoardRuntime).mockReturnValue(core as never);

      vi.mocked(resolveEffectiveAllowFromLists).mockReturnValue({
        effectiveAllowFrom: [],
        effectiveGroupAllowFrom: ["bob"],
      });

      await handlePulseBoardInbound({
        message: makeGroupMessage({ senderUser: "alice" }),
        account: makeAccount({ groupPolicy: "allowlist", groupAllowFrom: ["bob"] }),
        config: makeConfig(),
        runtime,
      });

      expect(dispatchInboundReplyWithBase).not.toHaveBeenCalled();
    });

    it("dispatches group message when sender is in group allowlist", async () => {
      const { core, runtime } = makeRuntime();
      vi.mocked(getPulseBoardRuntime).mockReturnValue(core as never);

      // Sender matches effective group allowlist
      vi.mocked(resolveEffectiveAllowFromLists).mockReturnValue({
        effectiveAllowFrom: [],
        effectiveGroupAllowFrom: ["alice"],
      });

      await handlePulseBoardInbound({
        message: makeGroupMessage({ senderUser: "alice" }),
        account: makeAccount({ groupPolicy: "allowlist", groupAllowFrom: ["alice"] }),
        config: makeConfig(),
        runtime,
      });

      expect(dispatchInboundReplyWithBase).toHaveBeenCalledOnce();
    });
  });

  describe("mention gate", () => {
    it("drops group message when requireMention=true and not mentioned", async () => {
      const { core, runtime } = makeRuntime();
      // requireMention defaults to true in policy when no explicit config
      vi.mocked(core.channel.mentions.matchesMentionPatterns).mockReturnValue(false);
      vi.mocked(getPulseBoardRuntime).mockReturnValue(core as never);

      vi.mocked(resolveEffectiveAllowFromLists).mockReturnValue({
        effectiveAllowFrom: [],
        effectiveGroupAllowFrom: ["alice"],
      });

      await handlePulseBoardInbound({
        message: makeGroupMessage({ text: "just chatting", senderUser: "alice" }),
        account: makeAccount({
          groupPolicy: "allowlist",
          groupAllowFrom: ["alice"],
          groups: { "#general": { requireMention: true } },
        }),
        config: makeConfig(),
        runtime,
      });

      // With requireMention=true and no mention, the message should be dropped
      expect(dispatchInboundReplyWithBase).not.toHaveBeenCalled();
    });

    it("dispatches group message when requireMention=false", async () => {
      const { core, runtime } = makeRuntime();
      vi.mocked(core.channel.mentions.matchesMentionPatterns).mockReturnValue(false);
      vi.mocked(getPulseBoardRuntime).mockReturnValue(core as never);

      vi.mocked(resolveEffectiveAllowFromLists).mockReturnValue({
        effectiveAllowFrom: [],
        effectiveGroupAllowFrom: ["alice"],
      });

      await handlePulseBoardInbound({
        message: makeGroupMessage({ text: "just chatting", senderUser: "alice" }),
        account: makeAccount({
          groupPolicy: "allowlist",
          groupAllowFrom: ["alice"],
          groups: { "#general": { requireMention: false } },
        }),
        config: makeConfig(),
        runtime,
      });

      expect(dispatchInboundReplyWithBase).toHaveBeenCalledOnce();
    });
  });

  describe("ctxPayload shape", () => {
    it("sets From=pulseboard:<senderUser> for DM messages", async () => {
      const { core, runtime } = makeRuntime();
      vi.mocked(getPulseBoardRuntime).mockReturnValue(core as never);

      vi.mocked(resolveEffectiveAllowFromLists).mockReturnValue({
        effectiveAllowFrom: ["alice"],
        effectiveGroupAllowFrom: [],
      });

      await handlePulseBoardInbound({
        message: makeDmMessage({ senderUser: "alice", target: "alice" }),
        account: makeAccount({ dmPolicy: "allowlist", allowFrom: ["alice"] }),
        config: makeConfig(),
        runtime,
      });

      expect(core.channel.reply.finalizeInboundContext).toHaveBeenCalledWith(
        expect.objectContaining({
          From: "pulseboard:alice",
          ChatType: "direct",
          Provider: "pulseboard",
        }),
      );
    });

    it("sets From=pulseboard:board:<target> for group messages", async () => {
      const { core, runtime } = makeRuntime();
      vi.mocked(getPulseBoardRuntime).mockReturnValue(core as never);

      vi.mocked(resolveEffectiveAllowFromLists).mockReturnValue({
        effectiveAllowFrom: [],
        effectiveGroupAllowFrom: ["alice"],
      });

      await handlePulseBoardInbound({
        message: makeGroupMessage({ target: "#general", senderUser: "alice" }),
        account: makeAccount({
          groupPolicy: "allowlist",
          groupAllowFrom: ["alice"],
          groups: { "#general": { requireMention: false } },
        }),
        config: makeConfig(),
        runtime,
      });

      expect(core.channel.reply.finalizeInboundContext).toHaveBeenCalledWith(
        expect.objectContaining({
          From: "pulseboard:board:#general",
          ChatType: "group",
          Provider: "pulseboard",
          Surface: "pulseboard",
        }),
      );
    });
  });

  describe("control command gate", () => {
    it("drops group message when command gate blocks it", async () => {
      const { core, runtime } = makeRuntime();
      vi.mocked(core.channel.text.hasControlCommand).mockReturnValue(true);
      vi.mocked(getPulseBoardRuntime).mockReturnValue(core as never);

      vi.mocked(resolveControlCommandGate).mockReturnValue({
        commandAuthorized: false,
        shouldBlock: true,
      });
      vi.mocked(resolveEffectiveAllowFromLists).mockReturnValue({
        effectiveAllowFrom: [],
        effectiveGroupAllowFrom: ["alice"],
      });

      await handlePulseBoardInbound({
        message: makeGroupMessage({
          text: "/somecommand",
          senderUser: "alice",
        }),
        account: makeAccount({
          groupPolicy: "allowlist",
          groupAllowFrom: ["alice"],
          groups: { "#general": { requireMention: false } },
        }),
        config: makeConfig(),
        runtime,
      });

      expect(dispatchInboundReplyWithBase).not.toHaveBeenCalled();
    });
  });
});
